mxEditor.add:
function (div)
{
	console.log('createTasks...');

	// View filter panel — always visible, not a .task.
	// One checkbox per distinct Transition method name. Unchecking hides
	// edges of that type so overlapping flows are easier to read.
	var view = document.createElement('div');
	view.id = 'ViewFilter';
	view.className = 'view-panel';
	view.innerHTML =
		'<div class="view-header">' +
			'<b>View</b> ' +
			'<a href="#" id="view-show-all">all</a> | ' +
			'<a href="#" id="view-hide-all">none</a>' +
		'</div>' +
		'<div id="view-methods"></div>';
	div.appendChild(view);

	if (window.flowTasks && window.flowTasks.initView) {
		window.flowTasks.initView(this.graph);
	}

	var sep = document.createElement('hr');
	sep.className = 'view-sep';
	div.appendChild(sep);

	// State properties panel
	var state = document.createElement('div');
	state.id = 'State';
	state.className = 'task';
	state.style.display = 'none';
	div.appendChild(state);
	$('#State').load('./state.html #state-view');

	// Ingress cloud properties panel (same template as State)
	var ingress = document.createElement('div');
	ingress.id = 'Ingress';
	ingress.className = 'task';
	ingress.style.display = 'none';
	div.appendChild(ingress);
	$('#Ingress').load('./state.html #state-view');

	// Egress cloud properties panel (same template as State)
	var egress = document.createElement('div');
	egress.id = 'Egress';
	egress.className = 'task';
	egress.style.display = 'none';
	div.appendChild(egress);
	$('#Egress').load('./state.html #state-view');

	// Transition properties panel
	var transition = document.createElement('div');
	transition.id = 'Transition';
	transition.className = 'task';
	transition.style.display = 'none';
	div.appendChild(transition);
	$('#Transition').load('./transition.html #transition-view', function() {
		$('#transition-tabs').tabs();
	});

	// Global config panel (FlowModel root)
	var config = document.createElement('div');
	config.id = 'FlowModel';
	config.className = 'task';
	config.style.display = 'none';
	div.appendChild(config);
	$('#FlowModel').load('./config.html #config-view');
}

function (div)
{
	console.log('refreshTasks...');
	if (this.tasks != null)
	{
		var title = 'FlowModel';

		$('.task').css('display','none');

		var selectedCell = this.graph.getSelectionCell();
		window.flowGraph = this.graph;

		if (selectedCell != null && selectedCell.value != null) {
			title = selectedCell.value.tagName;
			window.flowSelectedCell = selectedCell;
		} else {
			// Nothing selected — show the global FlowModel config
			var rootCell = this.graph.getModel().getCell('0');
			window.flowSelectedCell = rootCell;
			title = 'FlowModel';
		}

		this.tasks.setTitle(title);
		$('#'+title).css('display','block');

		if (typeof window.flowTasks !== 'undefined' && window.flowTasks.loadFromCell) {
			window.flowTasks.loadFromCell(window.flowSelectedCell);
		}
	}
}

function (div)
{
	console.log('showTasks...');

	if (this.tasks == null) {
		var div = document.createElement('div');
		div.style.padding = '8px';

		var w = document.body.clientWidth;
		var wnd = new mxWindow(mxResources.get(this.tasksResource)
				|| this.tasksResource, div, w - 320, this.tasksTop, 300);
		wnd.setClosable(true);
		wnd.destroyOnClose = false;

		var funct = mxUtils.bind(this, function(sender) {
			this.refreshTasks(div);
		});

		this.graph.getModel().addListener(mxEvent.CHANGE, funct);
		this.graph.getSelectionModel().addListener(mxEvent.CHANGE, funct);
		this.graph.addListener(mxEvent.ROOT, funct);

		if (this.tasksWindowImage != null) {
			wnd.setImage(this.tasksWindowImage);
		}

		this.tasks = wnd;

		this.createTasks(div);
	}

	this.tasks.setVisible(true);
}
